# BAD: Security headers disappear in /api/ location

server {
    listen 443 ssl;
    server_name example.com;

    # Server-level headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;

    location / {
        # Inherits server headers ✓
        try_files $uri $uri/ =404;
    }

    location /api/ {
        # This add_header REPLACES server-level headers!
        # X-Frame-Options and X-Content-Type-Options are GONE!
        add_header X-Custom "value" always;
        proxy_pass http://backend;
    }
}

# GOOD: All headers at server level, no location add_header

server {
    listen 443 ssl;
    server_name example.com;

    # Security headers — server level
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;
    server_tokens off;

    location / {
        # NO add_header here — inherits server headers ✓
        try_files $uri $uri/ =404;
    }

    location /api/ {
        # NO add_header here — inherits server headers ✓
        proxy_pass http://backend;
    }
}

# If you MUST add a location-specific header, repeat all security headers

server {
    listen 443 ssl;
    server_name example.com;

    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;
    server_tokens off;

    location / {
        try_files $uri $uri/ =404;
    }

    location /api/ {
        # MUST repeat ALL security headers here
        add_header X-Frame-Options "SAMEORIGIN" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;
        add_header X-Custom "value" always;
        proxy_pass http://backend;
    }
}

# /etc/nginx/snippets/security-headers.conf
# One file to rule them all

add_header X-Frame-Options "SAMEORIGIN" always;
add_header X-Content-Type-Options "nosniff" always;
add_header Referrer-Policy "strict-origin-when-cross-origin" always;
add_header Permissions-Policy "camera=(), microphone=(), geolocation=()" always;
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;
add_header X-XSS-Protection "1; mode=block" always;
server_tokens off;

# Usage in each server block:
# server {
#     include /etc/nginx/snippets/security-headers.conf;
#     # ...
# }

# Only enable preload if you are absolutely certain
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

# Submit your domain at: https://hstspreload.org/

# Phase 1: Test (5 minutes)
add_header Strict-Transport-Security "max-age=300; includeSubDomains" always;

# Phase 2: Production (1 year)
add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;

# Phase 3: Preload (irreversible)
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

# DENY — Never allow iframing (most secure)
add_header X-Frame-Options "DENY" always;

# SAMEORIGIN — Allow iframing only on same origin (recommended)
add_header X-Frame-Options "SAMEORIGIN" always;

# ALLOW-FROM — Deprecated, not supported in modern browsers
# Use Content-Security-Policy frame-ancestors instead

# CSP frame-ancestors is the modern replacement with more granular control

# Block all iframing (equivalent to DENY)
add_header Content-Security-Policy "frame-ancestors 'none'" always;

# Allow same origin (equivalent to SAMEORIGIN)
add_header Content-Security-Policy "frame-ancestors 'self'" always;

# Allow specific external domains
add_header Content-Security-Policy "frame-ancestors 'self' https://trusted-app.example.com" always;

# Best practice: set BOTH headers for backward compatibility
add_header X-Frame-Options "SAMEORIGIN" always;
add_header Content-Security-Policy "frame-ancestors 'self'" always;

add_header X-Content-Type-Options "nosniff" always;

# That is it. The only valid value is "nosniff".
# There is no reason not to set this header on every response.

# Strict CSP — start here, then relax as needed
add_header Content-Security-Policy "
    default-src 'self';
    script-src 'self';
    style-src 'self' 'unsafe-inline';
    img-src 'self' data: https:;
    font-src 'self';
    connect-src 'self';
    frame-ancestors 'self';
    form-action 'self';
    base-uri 'self';
    object-src 'none';
" always;

# Moderate CSP — suitable for most web applications
add_header Content-Security-Policy "
    default-src 'self';
    script-src 'self' 'unsafe-inline' 'unsafe-eval';
    style-src 'self' 'unsafe-inline';
    img-src 'self' data: https: blob:;
    font-src 'self' data:;
    connect-src 'self' https://api.example.com wss:;
    frame-src 'self' https://www.youtube.com;
    frame-ancestors 'self';
    form-action 'self';
    base-uri 'self';
    object-src 'none';
" always;

# Permissive CSP — for sites that embed many external resources
add_header Content-Security-Policy "
    default-src 'self' http: https: data: blob: 'unsafe-inline' 'unsafe-eval';
    script-src 'self' 'unsafe-inline' 'unsafe-eval' https:;
    style-src 'self' 'unsafe-inline' https:;
    img-src 'self' data: https: blob:;
    font-src 'self' data: https:;
    connect-src 'self' https: wss:;
    frame-src 'self' https:;
    frame-ancestors 'self';
    form-action 'self';
    base-uri 'self';
    object-src 'none';
" always;

# Phase 1: Test with Report-Only — violations are logged but NOT blocked
add_header Content-Security-Policy-Report-Only "
    default-src 'self';
    script-src 'self';
    style-src 'self' 'unsafe-inline';
    img-src 'self' data:;
    font-src 'self';
    connect-src 'self';
    frame-ancestors 'self';
    form-action 'self';
    base-uri 'self';
    object-src 'none';
    report-uri /csp-violations;
" always;

# Monitor your violation reports, then switch to enforcement mode:
# add_header Content-Security-Policy "..." always;

# Recommended: strict-origin-when-cross-origin
add_header Referrer-Policy "strict-origin-when-cross-origin" always;

# Maximum privacy (but may break some analytics)
add_header Referrer-Policy "no-referrer" always;

# Good balance for most sites
add_header Referrer-Policy "strict-origin-when-cross-origin" always;

# Enable filter, block if XSS detected (recommended for legacy support)
add_header X-XSS-Protection "1; mode=block" always;

# Disable filter (use with CSP instead)
add_header X-XSS-Protection "0" always;

# Enable filter with sanitization (not recommended — can introduce XSS)
add_header X-XSS-Protection "1" always;

# /etc/nginx/snippets/security-headers.conf
# Include this in every server block

# === HSTS — Force HTTPS (only for HTTPS servers) ===
# Start with max-age=300 for testing, then increase to 31536000
# Use preload only if you are certain (it is hard to undo)
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

# === Prevent Clickjacking ===
add_header X-Frame-Options "SAMEORIGIN" always;

# === Prevent MIME Sniffing ===
add_header X-Content-Type-Options "nosniff" always;

# === Legacy XSS Protection ===
add_header X-XSS-Protection "1; mode=block" always;

# === Referrer Policy ===
add_header Referrer-Policy "strict-origin-when-cross-origin" always;

# === Permissions Policy ===
add_header Permissions-Policy "
    camera=(),
    microphone=(),
    geolocation=(),
    payment=(),
    usb=(),
    accelerometer=(),
    gyroscope=(),
    magnetometer=(),
    midi=(),
    sync-xhr=(),
    display-capture=()
" always;

# === Content Security Policy (customize for your app) ===
add_header Content-Security-Policy "
    default-src 'self';
    script-src 'self' 'unsafe-inline' 'unsafe-eval';
    style-src 'self' 'unsafe-inline';
    img-src 'self' data: https: blob:;
    font-src 'self' data:;
    connect-src 'self' https: wss:;
    frame-src 'self' https:;
    frame-ancestors 'self';
    form-action 'self';
    base-uri 'self';
    object-src 'none';
" always;

# === Hide NGINX version ===
server_tokens off;

# /etc/nginx/sites-available/example.com

server {
    listen 443 ssl http2;
    server_name example.com;

    ssl_certificate /etc/letsencrypt/live/example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;

    # Include security headers
    include /etc/nginx/snippets/security-headers.conf;

    root /var/www/example;
    index index.html;

    location / {
        # No add_header = inherits from server block
        try_files $uri $uri/ =404;
    }

    location /api/ {
        # No add_header = inherits from server block
        proxy_pass http://backend;
    }
}

# /etc/nginx/nginx.conf
http {
    # ...
    include /etc/nginx/snippets/security-headers.conf;
    # ...
    include /etc/nginx/sites-enabled/*;
}

# !! WARNING: If ANY server or location block uses add_header,
# the globally included headers will be REPLACED for that block.
# Only use this method if you NEVER use add_header in server/location blocks.

# HTTP redirect server
server {
    listen 80;
    server_name example.com;
    include /etc/nginx/snippets/security-headers.conf;
    return 301 https://$server_name$request_uri;
}

# HTTPS server
server {
    listen 443 ssl http2;
    server_name example.com;
    include /etc/nginx/snippets/security-headers.conf;

    ssl_certificate /etc/letsencrypt/live/example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;

    root /var/www/example;
    index index.html;

    location / {
        try_files $uri $uri/ =404;
    }
}

# WRONG — headers missing on error pages
add_header Strict-Transport-Security "max-age=63072000" always;  # OK
add_header X-Frame-Options "SAMEORIGIN";  # MISSING always — no header on 404/500

# CORRECT
add_header Strict-Transport-Security "max-age=63072000" always;
add_header X-Frame-Options "SAMEORIGIN" always;

# WRONG
server {
    add_header X-Frame-Options "SAMEORIGIN" always;
    location / {
        add_header X-Content-Type-Options "nosniff" always;  # X-Frame-Options LOST!
    }
}

# CORRECT
server {
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    location / {
        # No add_header = inherits from server
    }
}

# CORRECT: HSTS only on HTTPS
server {
    listen 80;
    server_name example.com;
    # NO HSTS here
    return 301 https://$server_name$request_uri;
}

server {
    listen 443 ssl;
    server_name example.com;
    add_header Strict-Transport-Security "max-age=63072000" always;
}

# /etc/nginx/sites-available/static-site.conf

# HTTP redirect
server {
    listen 80;
    listen [::]:80;
    server_name example.com www.example.com;
    include /etc/nginx/snippets/security-headers.conf;
    return 301 https://$server_name$request_uri;
}

# HTTPS server
server {
    listen 443 ssl http2;
    listen [::]:443 ssl http2;
    server_name example.com www.example.com;

    ssl_certificate /etc/letsencrypt/live/example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/example.com/privkey.pem;
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    ssl_prefer_server_ciphers off;
    ssl_session_cache shared:SSL:10m;
    ssl_session_timeout 1d;

    root /var/www/example;
    index index.html;

    include /etc/nginx/snippets/security-headers.conf;

    # Static asset caching
    location ~* \.(css|js|svg|woff2?)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        access_log off;
        # Inherits security headers from server level ✓
    }

    location ~* \.(jpg|jpeg|png|gif|ico|webp)$ {
        expires 30d;
        add_header Cache-Control "public, immutable";
        access_log off;
        # Inherits security headers from server level ✓
    }

    location / {
        try_files $uri $uri/ =404;
    }
}

# /etc/nginx/sites-available/api.conf

server {
    listen 443 ssl http2;
    server_name api.example.com;

    ssl_certificate /etc/letsencrypt/live/api.example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/api.example.com/privkey.pem;

    include /etc/nginx/snippets/security-headers.conf;

    # CSP for API (stricter — no inline anything)
    add_header Content-Security-Policy "default-src 'none'; frame-ancestors 'none';" always;

    # CORS headers
    add_header Access-Control-Allow-Origin "https://app.example.com" always;
    add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS" always;
    add_header Access-Control-Allow-Headers "Authorization, Content-Type" always;

    location / {
        proxy_pass http://api_backend;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

# /etc/nginx/sites-available/spa.conf

server {
    listen 443 ssl http2;
    server_name app.example.com;

    ssl_certificate /etc/letsencrypt/live/app.example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/app.example.com/privkey.pem;

    root /var/www/app/dist;
    index index.html;

    include /etc/nginx/snippets/security-headers.conf;

    # SPA needs less restrictive CSP for dev tools
    add_header Content-Security-Policy "
        default-src 'self';
        script-src 'self' 'unsafe-inline' 'unsafe-eval';
        style-src 'self' 'unsafe-inline';
        img-src 'self' data: https: blob:;
        font-src 'self' data:;
        connect-src 'self' https://api.example.com wss:;
        frame-src 'none';
        frame-ancestors 'none';
        form-action 'self';
        base-uri 'self';
        object-src 'none';
    " always;

    # API proxy (NO add_header here — inherits from server)
    location /api/ {
        proxy_pass http://127.0.0.1:3000/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }

    # Static files
    location ~* \.(js|css)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        access_log off;
    }

    # SPA routing
    location / {
        try_files $uri $uri/ /index.html;
    }
}

# Prevent caching of sensitive pages
location /admin/ {
    add_header Cache-Control "no-store, no-cache, must-revalidate, private" always;
    add_header Pragma "no-cache" always;
    add_header Expires "0" always;
}

# Allow caching of public resources
location ~* \.(css|js|png)$ {
    expires 1y;
    add_header Cache-Control "public, immutable" always;
}
